import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir = os.path.abspath(dir_path)
        target_file = os.path.abspath(os.path.join(base_dir, filename))

        # Prevent path traversal (CWE-22)
        if os.path.commonpath([base_dir, target_file]) != base_dir:
            return ""

        with open(target_file, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ""

