import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        dest_path = os.path.abspath(dest_path)
        with tarfile.open(tar_path, 'r:*') as tar:
            members = tar.getmembers()
            for member in members:
                member_path = os.path.abspath(os.path.join(dest_path, member.name))
                if not (member_path == dest_path or member_path.startswith(dest_path + os.sep)):
                    return False
                if member.issym() or member.islnk():
                    link_path = os.path.abspath(os.path.join(os.path.dirname(member_path), member.linkname))
                    if not (link_path == dest_path or link_path.startswith(dest_path + os.sep)):
                        return False
            tar.extractall(dest_path, members=members)
        return True
    except Exception:
        return False

