from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(resolve_entities=False, no_network=True, load_dtd=False)
    try:
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.XMLSyntaxError:
        return None

    query = "/students/student[username=$user and password=$pwd]"
    result = root.xpath(query, user=username, pwd=password)

    if not result:
        return None

    student = result[0]
    info = {}
    for child in student:
        info[child.tag] = child.text if child.text is not None else ""
    return info

import os

def save_secrete_file(directory: str, filename: str, content: str) -> None:
    if not filename:
        raise ValueError("Filename cannot be empty")

    dir_path = os.path.realpath(directory)

    if not os.path.exists(dir_path):
        os.makedirs(dir_path, mode=0o700, exist_ok=True)

    file_path = os.path.realpath(os.path.join(dir_path, filename))

    try:
        if os.path.commonpath([dir_path, file_path]) != dir_path:
            raise ValueError("Invalid filename")
    except ValueError:
        raise ValueError("Invalid filename")

    if os.path.isdir(file_path):
        raise ValueError("Invalid filename")

    fd = os.open(file_path, os.O_WRONLY | os.O_CREAT | os.O_TRUNC, 0o600)
    try:
        if hasattr(os, 'fchmod'):
            os.fchmod(fd, 0o600)
        else:
            os.chmod(file_path, 0o600)
    except:
        os.close(fd)
        raise

    with os.fdopen(fd, 'wb') as f:
        f.write(content.encode('utf-8'))

