import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    user_input = input("Enter command: ")

    try:
        args = shlex.split(user_input)
    except ValueError:
        return "Invalid command syntax"

    if not args:
        return "No command entered"

    # Whitelist of allowed commands to prevent Command Injection (CWE-78)
    allowed_commands = ['ls', 'pwd', 'date', 'echo']

    if args[0] not in allowed_commands:
        return "Command not allowed"

    try:
        # Using shell=False and a list of arguments to prevent shell injection
        result = subprocess.run(args, shell=False, capture_output=True, text=True, check=True)
        return result.stdout
    except subprocess.CalledProcessError as e:
        return e.stderr
    except Exception as e:
        return str(e)

