def eval_code():
    '''
    Get the user input from the request, 
    compile it into a python code, then execute it.
    '''
    user_input = request.args.get("code", "")
    try:
        # Attempt to evaluate as an expression first
        compiled_code = compile(user_input, "<string>", "eval")
        result = eval(compiled_code, {"__builtins__": {}})
        return str(result)
    except SyntaxError:
        # If it's a syntax error (e.g., statements like assignments), execute as code
        compiled_code = compile(user_input, "<string>", "exec")
        exec(compiled_code, {"__builtins__": {}})
        return "Executed"
    except Exception as e:
        return str(e)

