import io

class SafeUnpickler(cPickle.Unpickler):
    def find_class(self, module, name):
        # Block arbitrary class loading to prevent code execution
        raise cPickle.UnpicklingError(f"global '{module}.{name}' is forbidden")

def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    auth_token = headers.get("AuthToken")
    if not auth_token:
        return None

    try:
        decoded_bytes = base64.b64decode(auth_token)
        # Use restricted unpickler to safely load basic data structures
        token = SafeUnpickler(io.BytesIO(decoded_bytes)).load()
    except Exception:
        return None

    if isinstance(token, dict) and token.get("valid"):
        return token.get("data")

    return None

import base64
import json

def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with JSON to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    auth_token = headers.get("AuthToken")
    if not auth_token:
        return None

    try:
        decoded_bytes = base64.b64decode(auth_token)
        token = json.loads(decoded_bytes)
    except Exception:
        return None

    if isinstance(token, dict) and token.get("valid"):
        return token.get("data")

    return None
